INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-acfc4025-moex-00072', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「我們常覺得是自己在做決定，但事實上在缺乏資訊時，會藉由觀察別人， 盡量蒐集片段的資料，然後加以模仿。模仿可以是個正當的策略，是一種 『社會學習』，透過和其他人的互動來學習，比自己獨力應付狀況時更聰 明些。不過模仿卻也經常把大家帶離正軌，因為模仿並不會產生任何新資 訊，只是擴大一些舊資訊可以帶來的效果，並且不管資訊是真是假。」 根據上文，下列選項最符合文意的是：', '["人們在絕大多數時間所下的決定，其實都並非出自自我判斷", "模仿其實也是不錯的學習方式，只要能在正當運用的範圍內", "社會學習意指由社會群體來做決定，以避免專斷獨裁的危險", "資訊充沛的時代，蒐集資料、觀察別人，是正確的學習策略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00073', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「前不久，我返家，彷彿已經老去卻又元氣十足的奶奶，親暱地坐在我身 邊問我人生前途的種種課題，那些我答不出來也無意抵達的目標、方向、 可能。對話像飄搖的小舟行駛在晴日之海，懶洋洋。」 根據上文，下列選項最接近祖母和作者對話狀態的是：', '["作者有一搭沒一搭地被動回應祖母", "作者積極回應祖母，兩人聊得愉快", "祖母明知故問，作者只能羞愧沉默", "兩人互相試探，宛如小型的攻防戰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00074', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '常言道：「這世界最可敬的事，就是比你聰明的人，卻比你還更加認真， 積極求上。」下列選項，最接近文意的是：', '["學如逆水行舟，不進則退", "一分天才，九十九分努力", "坐等機會，終將一事無成", "學海無涯，惟勤勞能補拙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00075', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「坊間攝影書，最常提到的關鍵字不外乎是：景深、快門、光圈，種種競 選口號般速成式的激情，但我相信唯有勇氣、體貼與好奇，才能讓攝影與 生活產生更緊密的聯繫，我們似乎總是忘記，拍照最常用到的其實不是單 眼相機，是你的那雙眼睛。」 根據上文，下列選項何者最符合文意？', '["攝影書常為求速成而內容不實", "攝影要能等待時機、掌握變化", "具備審美的眼光就能拍出好照片", "養成攝影之眼需要細膩觀察生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00076', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「臺灣人許多時候將『飲食』視為社交活動，對食物很疏離，只對入口的 東西有慾望，但對食品產業結構、到身體產生什麼變化，不太關心，而且 過度追求『便宜大碗』的氛圍下，忽略食材、人工成本，廠商於是拚命壓 低成本，甚至走上偏路，消費者成了不健康競爭的間接推手。『不把態度 擺正，再多規範、溯源，都可以破解』，若要建立美食王國聲譽，臺灣消 費者可以做得更多。 」 根據上文，下列選項最符合文意的是：', '["食品法規無助於食品安全，消費者必須謹慎挑選", "廠商拚命壓低成本，以薄利多銷手法衝刺市占率", "消費者有健全的飲食態度，才能從源頭強化食安", "社會的停滯性通膨，導致消費者追求便宜又大碗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00077', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「人在工作時，由於精神專注，意志集中，自能煥發出生命的光芒；在無 所事事時，人立即顯得無精打采，悵然若失，既看不到眼神中激昂的鬥志， 動作中的意氣風發也頹然若止。」 下列選項，最合乎本文意旨的是：', '["精神專注可提升工作效率", "人在專心工作時最具光彩", "工作讓人年輕且活得充實", "離開工作會讓人獲得自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00078', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「弓頭鯨的名稱得自巨大而獨特的弓狀頭顱。其軀體非常沉重，雖然至今 還未曾整個或局部地被秤過，一般相信就其體長來看，應該比其他的鯨都 重。經常與一角鯨、白鯨結伴，是生活在北極的唯一大型鯨類動物。鯨脂 厚達70公分，有助其禦寒；能穿破厚達30公分的冰層，為自己開鑿呼吸 孔。有顯著的白色下巴，身上沒有皮繭，也沒有背鰭，這些特徵應足以用 來辨認。」 根據上文，下列選項正確的是：', '["弓頭鯨之名來自其弓狀的頭顱，可能是世界上最長的鯨豚", "弓頭鯨、一角鯨、白鯨，都是棲息於北極的大型鯨類動物", "弓頭鯨擁有厚重的脂肪，主要功能在於抵禦棲地嚴酷的低溫", "弓頭鯨全身呈現黑色、藍黑色，但只有胸鰭和尾鰭是深褐色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00079', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「迷迭香具有殺菌、消毒、防蟲的功效，在無法用科學證實迷迭香效用的 年代裡，古時候的人相信迷迭香可以驅魔。因為迷迭香的味道與香氣過於 濃郁，拿來料理時要特別注意分量。大部分料理方式是將新鮮的迷迭香鋪 在羊肉下面，或塞進雞或魚的肚裡，再放入烤箱。另外，葉子也可以加進 番茄湯裡熬煮，製作餅乾、麵包時也常會加入迷迭香。」 根據上文，關於迷迭香的敘述，下列選項何者正確？', '["用途不限於料理", "葉子不適合食用", "口味溫和，煮菜時多多益善", "只能用於肉類料理，如羊、雞、魚等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00080', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「金融風暴之後，世界恐慌已湧向職場，倒閉嚴重，沒倒的公司裡也潛在 著失業危機。與其當機不動，還不如積極培養自己的品牌力，人脈關係， 做好相關市場調查，啟動腦中的偵測天線，早日重新開機，而重新開機前， 心理上不要在乎升官速度變慢。」 下列選項，最符合上文旨趣的是：', '["適時關機，如同休息為了走更長的路", "金融危機可能讓頭腦當機，無法適應", "不畏環境變數，累積自己實力方為上策", "思考升官速度快慢，不如避免金融危機"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL),
  ('disabled-acfc4025-moex-00081', 'disabled-acfc4025', 'disabled-acfc4025-moex-112-34c7f7f6', 'sub-disabled-acfc4025-04', NULL, 'single_choice', '「網路搜尋能提升人們的『認知自尊』，即對於自身記性和處理資訊能力 的感受往往自我感覺良好，時常搞混自己與別人擁有的知識。問題在於， 花個幾小時仔細瀏覽醫學網站，不可能取代多年訓練培育出來的專業，以 及據此做出的合格醫療診斷。醫療專業人員表示，做過網路搜尋的病患知 道的資訊跟沒查網路的病患差不多。然而，他們卻容易對自己的醫療知識 很有信心，進而造成不相信專業人員的診斷，或寧願尋求另類療法。」 下列選項，何者最符合本文意旨？', '["自我感覺良好者易錯判情勢而危及生命", "醫療專業高深，但是未必勝過另類療法", "知識取得容易，讓人產生無所不知的錯覺", "網路資訊破碎，實際上無助於問題的解決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:39:01+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "508", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電子工程"}'::jsonb, NULL)
